import { useState } from 'react';
import { useNavigate } from 'react-router-dom';
import { motion } from 'framer-motion';
import { propertiesData, getFilterOptions, filterProperties } from '../data/propertiesData';
import { useFavorites } from '../context/FavoritesContext';
import { useAuth } from '../context/AuthContext';
import { Home, Building2, Filter, X, Heart, Search } from 'lucide-react';

const Projects = () => {
  const navigate = useNavigate();
  const { isAuthenticated } = useAuth();
  const { isFavorite, toggleFavorite, getFavoritesCount } = useFavorites();
  
  const [filters, setFilters] = useState({
    category: 'All',
    listingType: 'All',
    propertyType: 'All',
    maxPrice: 50000000
  });
  const [searchQuery, setSearchQuery] = useState('');
  const [showMobileFilters, setShowMobileFilters] = useState(false);
  
  const filterOptions = getFilterOptions();
  
  const getFilteredProperties = () => {
    let filtered = propertiesData.filter(property => {
      if (filters.category !== 'All' && property.category !== filters.category) return false;
      if (filters.listingType !== 'All' && property.listingType !== filters.listingType) return false;
      if (filters.propertyType !== 'All' && property.propertyType !== filters.propertyType) return false;
      if (property.price > filters.maxPrice) return false;
      return true;
    });
    
    if (searchQuery.trim() !== '') {
      const query = searchQuery.toLowerCase().trim();
      filtered = filtered.filter(property => 
        property.title.toLowerCase().includes(query) ||
        property.location.toLowerCase().includes(query) ||
        property.propertyType.toLowerCase().includes(query)
      );
    }
    
    return filtered;
  };
  
  const filteredProperties = getFilteredProperties();
  
  const handleViewDetails = (propertyId) => {
    navigate(`/property/${propertyId}`);
  };

  const handleFavoriteClick = (e, property) => {
    e.stopPropagation();
    if (!isAuthenticated) {
      alert('Please login to save favorites');
      navigate('/login');
      return;
    }
    toggleFavorite(property);
  };

  const formatPrice = (price, listingType) => {
    if (listingType === 'Rent') {
      if (price >= 100000) return `₹${(price / 100000).toFixed(1)}L/month`;
      return `₹${price.toLocaleString('en-IN')}/month`;
    }
    if (listingType === 'Lease') {
      if (price >= 100000) return `₹${(price / 100000).toFixed(1)}L/year`;
      return `₹${price.toLocaleString('en-IN')}/year`;
    }
    if (price >= 10000000) return `₹${(price / 10000000).toFixed(2)} Cr`;
    if (price >= 100000) return `₹${(price / 100000).toFixed(1)} Lakhs`;
    return `₹${price.toLocaleString('en-IN')}`;
  };

  const getListingTypeColor = (type) => {
    switch(type) {
      case 'Sale': return 'bg-green-600';
      case 'Rent': return 'bg-blue-600';
      case 'Lease': return 'bg-purple-600';
      default: return 'bg-gray-600';
    }
  };

  const formatDisplayPrice = (price) => {
    if (price >= 10000000) return `₹${(price / 10000000).toFixed(2)} Cr`;
    if (price >= 100000) return `₹${(price / 100000).toFixed(1)} Lakhs`;
    if (price >= 1000) return `₹${(price / 1000).toFixed(0)}K`;
    return `₹${price}`;
  };

  return (
    <div className="bg-[#0a0a0a] min-h-screen pt-24 pb-16">
      <div className="container-custom">
        <div className="text-center mb-8">
          <h1 className="text-4xl font-bold text-white mb-3">Find Your Dream Property</h1>
          <p className="text-gray-400">Discover residential & commercial properties in Nashik</p>
        </div>
        
        {/* Search Bar */}
        <div className="mb-6">
          <div className="relative max-w-2xl mx-auto">
            <Search className="absolute left-4 top-1/2 transform -translate-y-1/2 text-gray-500" size={20} />
            <input
              type="text"
              placeholder="Search by property name, location, or type..."
              value={searchQuery}
              onChange={(e) => setSearchQuery(e.target.value)}
              className="w-full pl-12 pr-4 py-3 bg-[#111111] border border-gray-800 rounded-xl focus:outline-none focus:border-[#c8a45e] text-white"
            />
          </div>
        </div>
        
        <div className="lg:hidden mb-4">
          <button onClick={() => setShowMobileFilters(!showMobileFilters)} className="w-full bg-[#111111] border border-gray-800 rounded-lg py-3 flex items-center justify-center gap-2 text-white">
            <Filter size={18} /> {showMobileFilters ? 'Hide Filters' : 'Show Filters'}
          </button>
        </div>
        
        <div className={`bg-[#111111] rounded-xl p-5 mb-8 ${showMobileFilters ? 'block' : 'hidden lg:block'}`}>
          <div className="flex flex-wrap items-end gap-4">
            <div className="flex-1 min-w-[140px]">
              <label className="block text-xs text-gray-500 mb-1">Category</label>
              <select value={filters.category} onChange={(e) => setFilters({...filters, category: e.target.value, propertyType: 'All'})} className="w-full p-2.5 bg-[#0a0a0a] border border-gray-800 rounded-lg text-white">
                {filterOptions.categories.map(cat => <option key={cat} value={cat}>{cat}</option>)}
              </select>
            </div>
            <div className="flex-1 min-w-[120px]">
              <label className="block text-xs text-gray-500 mb-1">Listing Type</label>
              <select value={filters.listingType} onChange={(e) => setFilters({...filters, listingType: e.target.value})} className="w-full p-2.5 bg-[#0a0a0a] border border-gray-800 rounded-lg text-white">
                {filterOptions.listingTypes.map(type => <option key={type} value={type}>{type}</option>)}
              </select>
            </div>
            <div className="flex-1 min-w-[250px]">
              <label className="block text-xs text-gray-500 mb-1">Max Price</label>
              <input type="range" min="0" max="50000000" step="5000" value={filters.maxPrice} onChange={(e) => setFilters({...filters, maxPrice: parseInt(e.target.value)})} className="w-full" />
              <div className="text-right mt-1"><span className="text-sm font-bold text-[#c8a45e]">{formatDisplayPrice(filters.maxPrice)}</span></div>
            </div>
            <button onClick={() => setFilters({ category: 'All', listingType: 'All', propertyType: 'All', maxPrice: 50000000 })} className="px-5 py-2.5 bg-gray-800 text-white rounded-lg hover:bg-gray-700 transition">Reset</button>
          </div>
        </div>
        
        <div className="mb-6">
          <p className="text-gray-400"><span className="font-bold text-[#c8a45e] text-lg">{filteredProperties.length}</span> properties found</p>
        </div>
        
        <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6">
          {filteredProperties.map((property, index) => (
            <div key={property.id} className="bg-[#111111] rounded-xl overflow-hidden border border-gray-800 hover:border-[#c8a45e]/50 transition cursor-pointer" onClick={() => handleViewDetails(property.id)}>
              <div className="relative h-52 overflow-hidden bg-gray-900">
                <img src={property.images[0]} alt={property.title} className="w-full h-full object-cover transition-transform duration-500 hover:scale-110" onError={(e) => { e.target.src = 'https://images.unsplash.com/photo-1560448204-e02f11c3d0e2?w=800'; }} />
                <div className="absolute top-3 left-3"><span className={`${getListingTypeColor(property.listingType)} text-white px-2 py-1 rounded-lg text-xs font-semibold`}>{property.listingType}</span></div>
                <div className="absolute top-3 right-3"><span className="bg-[#c8a45e] text-black px-2 py-1 rounded-lg text-xs font-semibold">{property.propertyType}</span></div>
                <button onClick={(e) => handleFavoriteClick(e, property)} className="absolute bottom-3 right-3 p-2 bg-black/50 rounded-full hover:scale-110 transition">
                  <Heart size={18} className={isFavorite(property.id) ? 'text-red-500 fill-red-500' : 'text-white'} />
                </button>
              </div>
              <div className="p-4">
                <h3 className="text-lg font-bold text-white mb-1">{property.title}</h3>
                <p className="text-gray-500 text-sm mb-2">📍 {property.location}</p>
                <p className="text-[#c8a45e] font-bold text-xl">{formatPrice(property.price, property.listingType)}</p>
                <div className="flex gap-4 mt-3 text-sm text-gray-500">
                  {property.bedrooms > 0 && <span>🛏️ {property.bedrooms} BHK</span>}
                  <span>📐 {property.area_sqft} sq.ft</span>
                </div>
                <button onClick={(e) => { e.stopPropagation(); handleViewDetails(property.id); }} className="w-full mt-4 bg-[#c8a45e] text-black py-2.5 rounded-lg font-semibold hover:bg-[#b8923a] transition">
                  View Details →
                </button>
              </div>
            </div>
          ))}
        </div>
      </div>
    </div>
  );
};

export default Projects;
